
// Dexie removed - using Supabase only
const $=s=>document.getElementById(s.replace('#',''));
var HQ={lat:29.6986,lng:-95.1280,name:'Maid Bridge HQ',addr:'Deer Park, TX 77536'};
var map,MK={},A=[],Z=[],SC=[],CUST=[],LOGS=[],DND=[],hG=null,routeL=null,routeMks=[],drawnZ,pinM=false,gpsMarker=null,gpsWatchId=null;
var filt='all',expTyp='today',expFmt='csv',selSA=[],tsA={},idc={a:0,z:0,s:0},batchSel=new Set();
var routeOrigin={...HQ},pendOID=null,dispMeth='email';
var COL={pending:'#8E8E93',scheduled:'#007AFF',visited:'#FF9F0A',interested:'#30D158',converted:'#BF5AF2',declined:'#FF453A','not-home':'rgba(255,255,255,0.3)',callback:'#64D2FF'};
var ICO={pending:'fa-clock',scheduled:'fa-calendar-check',visited:'fa-eye',interested:'fa-star',converted:'fa-handshake',declined:'fa-times-circle','not-home':'fa-door-closed',callback:'fa-phone-alt'};

window.__mbInit=async()=>{initMap();await loadAll();upStats();render();$('scDt').value=$('dispDt').value=new Date().toISOString().split('T')[0];initSearch();initKB();fetchWeather();checkReminders();setInterval(checkReminders,60000);setTimeout(()=>{$('ld').classList.add('done');setTimeout(()=>$('ld').remove(),500)},1e3)};

// ═══ WEATHER ═══
function fetchWeather(){fetch('https://api.open-meteo.com/v1/forecast?latitude=29.6986&longitude=-95.1280&current=temperature_2m,weathercode&temperature_unit=fahrenheit&timezone=America/Chicago').then(r=>r.json()).then(d=>{const t=Math.round(d.current.temperature_2m);const wc=d.current.weathercode;const icons={0:'fa-sun',1:'fa-cloud-sun',2:'fa-cloud',3:'fa-cloud',45:'fa-smog',51:'fa-cloud-rain',61:'fa-cloud-showers-heavy',80:'fa-cloud-rain',95:'fa-bolt'};const ic=icons[wc]||'fa-cloud-sun';$('weatherStrip').innerHTML=`<i class="fas ${ic}"></i><span>${t}°F Deer Park</span>`}).catch(()=>{$('weatherStrip').innerHTML=`<i class="fas fa-cloud"></i><span>Weather N/A</span>`})}

// ═══ GPS TRACKING ═══
function toggleGPS(){if(gpsWatchId){navigator.geolocation.clearWatch(gpsWatchId);gpsWatchId=null;if(gpsMarker){map.removeLayer(gpsMarker);gpsMarker=null}msg('info','GPS Off','');return}if(!navigator.geolocation)return msg('error','GPS','Not supported');gpsWatchId=navigator.geolocation.watchPosition(pos=>{const{latitude:lat,longitude:lng}=pos.coords;if(gpsMarker)gpsMarker.setLatLng([lat,lng]);else{gpsMarker=L.marker([lat,lng],{icon:L.divIcon({className:'mic',html:'<div class="gps-dot"></div>',iconSize:[14,14],iconAnchor:[7,7]}),zIndexOffset:2000}).addTo(map)}},()=>msg('error','GPS','Access denied'),{enableHighAccuracy:true,maximumAge:5000});msg('success','GPS On','Tracking your position')}

// ═══ KEYBOARD SHORTCUTS ═══
function initKB(){document.addEventListener('keydown',e=>{if(e.target.tagName==='INPUT'||e.target.tagName==='TEXTAREA'||e.target.tagName==='SELECT')return;const k=e.key.toLowerCase();if(k==='p')startPin();else if(k==='r')openRouteBuilder();else if(k==='/')$('searchIn').focus();else if(k==='f')fitAll();else if(k==='h')goHQ();else if(k==='g')toggleGPS();else if(k==='?'){$('kbPanel').classList.toggle('vis')}else if(k==='escape'){closeRP();closeSV();clearRoute();closeOv('addrOv');closeOv('schedOv');closeOv('expOv');closeOv('dispOv');closeOv('originOv');closeOv('smsOv');$('kbPanel').classList.remove('vis');clearBatch()}})}

// ═══ REMINDERS ═══
function checkReminders(){const today=new Date().toISOString().split('T')[0];const due=A.filter(a=>a.followUp&&a.followUp<=today&&a.status!=='converted'&&a.status!=='declined');if(due.length){due.forEach(a=>{msg('warning','Reminder',a.street+' — follow-up due!')})}}

// ═══ BATCH SELECT ═══
function toggleBatch(id,ev){ev.stopPropagation();if(batchSel.has(id))batchSel.delete(id);else batchSel.add(id);render();$('batchBar').classList.toggle('vis',batchSel.size>0);$('batchCount').textContent=batchSel.size+' selected'}
async function batchUpdate(){const s=$('batchStatus').value;for(const id of batchSel){const a=A.find(x=>x.id===id);if(a){a.status=s;a.updatedAt=new Date().toISOString();a.visits.push({date:new Date().toISOString(),status:s});upsertCust(a);reMk(a)}}batchSel.clear();$('batchBar').classList.remove('vis');await saveAll();upStats();render();msg('success','Batch','Updated '+batchSel.size+' addresses')}
function clearBatch(){batchSel.clear();$('batchBar').classList.remove('vis');render()}

// ═══ DO NOT VISIT ═══
async function addDND(id){const a=A.find(x=>x.id===id);if(!a)return;if(!confirm('Add '+a.street+' to Do-Not-Visit list?'))return;DND.push({id:'dnd'+Date.now(),addressId:a.id,street:a.street,city:a.city,zip:a.zip,reason:prompt('Reason?')||'',addedAt:new Date().toISOString()});a.status='declined';reMk(a);await saveAll();upStats();render();addLog('status','DND Added',a.street);msg('info','DND',a.street+' added')}
function renderDND(){const el=$('dndP');el.innerHTML=`<div class="sec-h"><span>Do Not Visit</span><span class="badge">${DND.length}</span></div>`+(DND.length?DND.map(d=>`<div class="gc" style="padding:9px;margin-bottom:5px"><div style="font:700 11px var(--f)">${d.street}</div><div style="font:400 8px var(--f);color:var(--t3)">${d.reason||'No reason'} · ${new Date(d.addedAt).toLocaleDateString()}</div></div>`).join(''):'<div style="text-align:center;padding:16px;color:var(--t3)"><p style="font:500 9px var(--f)">No blocked addresses</p></div>')}

// ═══ FUNNEL ═══
function renderFunnel(){const el=$('funnelP');const t=A.length||1;const stages=[['Pending','pending',COL.pending],['Scheduled','scheduled',COL.scheduled],['Visited','visited',COL.visited],['Interested','interested',COL.interested],['Callback','callback',COL.callback],['Converted','converted',COL.converted],['Declined','declined',COL.declined],['Not Home','not-home',COL['not-home']]];el.innerHTML=`<div class="sec-h"><span>Conversion Funnel</span></div><div class="funnel">${stages.map(([label,status,color])=>{const count=A.filter(a=>a.status===status).length;const pct=(count/t*100);return`<div class="funnel-step"><span class="funnel-label" style="color:${color}">${label}</span><div style="flex:1;background:var(--sf);border-radius:3px;overflow:hidden"><div class="funnel-bar" style="width:${pct}%;background:${color};min-width:2px"></div></div><span class="funnel-count">${count}</span></div>`}).join('')}</div><div class="gc" style="padding:10px;margin-top:8px"><div style="font:500 9px var(--f);color:var(--t3);margin-bottom:4px">Conversion Rate</div><div style="font:900 24px var(--f);color:var(--g)">${t>1?((A.filter(a=>a.status==='converted').length/(t-1))*100).toFixed(1):0}%</div></div>`}

// ═══ SMS ═══
function copySMS(el){const text=el.textContent;navigator.clipboard.writeText(text).then(()=>msg('success','Copied','SMS template copied')).catch(()=>{})}

// ═══ DUPLICATE CHECK ═══
function isDuplicate(street,lat,lng){return A.some(a=>a.street.toLowerCase()===street.toLowerCase()||(Math.abs(a.lat-lat)<0.0001&&Math.abs(a.lng-lng)<0.0001))}
function isDND(lat,lng){return DND.some(d=>{const a=A.find(x=>x.id===d.addressId);return a&&Math.abs(a.lat-lat)<0.0002&&Math.abs(a.lng-lng)<0.0002})}

// ═══ STORAGE (Supabase only - see supabase-sync.js) ═══
async function saveAll(){console.log('[MB] saveAll placeholder - Supabase handles this')}
async function loadAll(){console.log('[MB] loadAll placeholder - Supabase handles this')}
function backupToFile(){dlFile(JSON.stringify({v:3,d:new Date().toISOString(),idc,A,Z,SC,CUST,LOGS,DND},null,2),'MaidBridge_Backup.json','application/json');msg('success','Backup','Downloaded')}
async function restoreFile(ev){const f=ev.target.files[0];if(!f||!confirm('Replace all data?'))return;const rd=new FileReader();rd.onload=async e=>{try{const d=JSON.parse(e.target.result);Object.values(MK).forEach(m=>map.removeLayer(m));MK={};drawnZ.clearLayers();idc=d.idc||idc;A=d.A||d.addresses||[];Z=d.Z||d.zones||[];SC=d.SC||d.schedules||[];CUST=d.CUST||d.customers||[];LOGS=d.LOGS||d.logs||[];DND=d.DND||d.dnd||[];A.forEach(mkMk);Z.forEach(z=>{if(z.bounds)L.polygon(z.bounds,{color:'#007AFF',fillOpacity:.12,weight:1.5,dashArray:'5,4',fillColor:'#007AFF'}).addTo(drawnZ).bindTooltip(z.name,{permanent:true,direction:'center'})});await saveAll();upStats();render();fitAll();msg('success','Restored','')}catch(err){msg('error','Error','Invalid file')}};rd.readAsText(f);ev.target.value=''}

// ═══ MAP ═══
function initMap(){map=L.map('map',{center:[HQ.lat,HQ.lng],zoom:17,zoomControl:false,attributionControl:false});const sat=L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',{maxZoom:20});const dk=L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png',{maxZoom:20});const st=L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:20});sat.addTo(map);L.control.layers({Satellite:sat,Dark:dk,Streets:st},null,{position:'topright'}).addTo(map);drawnZ=L.featureGroup().addTo(map);L.marker([HQ.lat,HQ.lng],{icon:L.divIcon({className:'mic',html:'<div class="hq-m"><i class="fas fa-building"></i></div>',iconSize:[36,36],iconAnchor:[18,18]}),zIndexOffset:1000}).addTo(map).bindPopup('<div class="pop"><h3>🏠 HQ</h3><p>'+HQ.addr+'</p></div>',{className:'cpop'});map.on('click',e=>{if(pinM){pinM=false;$('pinBtn').classList.remove('on');map.getContainer().style.cursor='';if(isDND(e.latlng.lat,e.latlng.lng))return msg('warning','DND','This address is on Do-Not-Visit list');revGeo(e.latlng.lat,e.latlng.lng)}})}

// ═══ SEARCH ═══
let acTimer=null;
function initSearch(){const inp=$('searchIn');inp.oninput=()=>{clearTimeout(acTimer);const q=inp.value.trim();if(q.length<3){hideAC();render();return}$('spin').style.display='block';acTimer=setTimeout(()=>searchNom(q),300)};inp.onfocus=()=>{if($('acDrop').children.length)$('acDrop').classList.add('vis')};document.onclick=e=>{if(!$('srchWrap').contains(e.target))hideAC()}}
function searchNom(q){fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(q+', Deer Park, TX')}&limit=8&addressdetails=1&viewbox=-95.16,29.74,-95.07,29.68&bounded=1`).then(r=>r.json()).then(res=>{$('spin').style.display='none';const d=$('acDrop');if(!res.length){d.innerHTML='<div class="ac-it"><div class="ac-ic"><i class="fas fa-info-circle"></i></div><div><div class="ac-m">No results</div></div></div>';d.classList.add('vis');return}d.innerHTML=res.map(r=>{const p=r.display_name.split(',');return`<div class="ac-it" onclick="pickAC(${r.lat},${r.lon},'${esc(p[0])}')"><div class="ac-ic"><i class="fas fa-map-marker-alt"></i></div><div><div class="ac-m">${p[0]}</div><div class="ac-s">${p.slice(1,3).join(',')}</div></div></div>`}).join('');d.classList.add('vis')}).catch(()=>{$('spin').style.display='none'})}
function pickAC(lat,lng,st){hideAC();$('searchIn').value=st;map.flyTo([lat,lng],19,{duration:.6});const ex=A.find(a=>Math.abs(a.lat-lat)<.0002&&Math.abs(a.lng-lng)<.0002);if(ex){setTimeout(()=>{if(MK[ex.id])MK[ex.id].openPopup()},700);return}openAddrForm(lat,lng,st)}
function hideAC(){$('acDrop').classList.remove('vis')}
function esc(s){return s?s.replace(/'/g,"\\'").replace(/"/g,'&quot;'):''}
function revGeo(lat,lng){msg('info','Locating…','');fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=18&addressdetails=1`).then(r=>r.json()).then(d=>{const a=d.address||{};openAddrForm(lat,lng,(a.house_number?a.house_number+' ':'')+(a.road||''),a.city||a.town||'Deer Park',a.postcode||'77536')}).catch(()=>openAddrForm(lat,lng))}
function openSV(lat,lng,st){$('svFrame').innerHTML=`<iframe src="https://www.google.com/maps?q=${lat},${lng}&layer=c&cbll=${lat},${lng}&cbp=12,0,0,0,0&output=svembed" allowfullscreen loading="lazy"></iframe><div style="position:absolute;bottom:0;left:0;right:0;padding:5px 8px;background:rgba(0,0,0,.7);display:flex;align-items:center;justify-content:space-between"><span style="font:500 8px var(--f);color:var(--t2)">${st||''}</span><a href="https://www.google.com/maps/@${lat},${lng},3a,75y,90t/data=!3m6!1e1" target="_blank" rel="noopener" style="font:700 8px var(--f);color:var(--p);text-decoration:none">Maps →</a></div>`;$('svBox').classList.add('vis');$('fab').style.bottom='280px'}
function closeSV(){$('svBox').classList.remove('vis');$('svFrame').innerHTML='';$('fab').style.bottom='14px'}

// ═══ LOGS & CUSTOMERS ═══
function addLog(type,title,detail){LOGS.unshift({id:'l'+Date.now()+Math.random().toString(36).slice(2,5),type,title,detail:detail||'',time:new Date().toISOString()});if(LOGS.length>500)LOGS=LOGS.slice(0,500)}
function renderLogs(){const el=$('logsP');const ic={add:{i:'fa-plus-circle',bg:'var(--gd)',c:'var(--g)'},update:{i:'fa-edit',bg:'var(--pd)',c:'var(--p)'},status:{i:'fa-exchange-alt',bg:'var(--od)',c:'var(--o)'},delete:{i:'fa-trash',bg:'var(--rd)',c:'var(--r)'},schedule:{i:'fa-calendar-check',bg:'var(--cd)',c:'var(--c)'},dispatch:{i:'fa-paper-plane',bg:'var(--gd)',c:'var(--g)'},route:{i:'fa-route',bg:'var(--pd)',c:'var(--p)'},export:{i:'fa-file-export',bg:'var(--vd)',c:'var(--v)'},convert:{i:'fa-handshake',bg:'var(--vd)',c:'var(--v)'}};el.innerHTML=`<div class="sec-h"><span>Log</span><span class="badge">${LOGS.length}</span></div>`+(LOGS.length?LOGS.slice(0,80).map(l=>{const x=ic[l.type]||ic.update;return`<div class="log-entry"><div class="log-icon" style="background:${x.bg};color:${x.c}"><i class="fas ${x.i}"></i></div><div><div class="log-title">${l.title}</div><div class="log-detail">${l.detail}</div><div class="log-time">${new Date(l.time).toLocaleString()}</div></div></div>`}).join(''):'<div style="padding:16px;text-align:center;color:var(--t3)">No activity</div>')}
function upsertCust(a){let c=CUST.find(x=>(x.phone&&x.phone===a.phone)||(x.street===a.street&&x.zip===a.zip));if(!c){c={id:'c'+Date.now(),street:a.street,city:a.city,zip:a.zip,owner:a.owner,phone:a.phone,email:a.email,firstSeen:new Date().toISOString(),interactions:[],status:'prospect',convertedAt:null};CUST.push(c)}c.owner=a.owner||c.owner;c.phone=a.phone||c.phone;c.interactions.push({date:new Date().toISOString(),type:a.status});if(a.status==='converted'&&!c.convertedAt){c.convertedAt=new Date().toISOString();c.status='client'}else if(a.status==='interested')c.status='hot-lead';else if(a.status==='callback')c.status='follow-up';else if(a.status==='declined')c.status='lost'}
function renderCust(){$('custP').innerHTML=`<div class="sec-h"><span>Leads</span><span class="badge">${CUST.length}</span></div><div class="stats" style="margin-bottom:8px"><div class="stat-c"><div class="stat-v" style="color:var(--g)">${CUST.filter(c=>c.status==='hot-lead').length}</div><div class="stat-l">Hot</div></div><div class="stat-c"><div class="stat-v" style="color:var(--v)">${CUST.filter(c=>c.status==='client').length}</div><div class="stat-l">Clients</div></div></div>`+(CUST.length?CUST.map(c=>`<div class="acard" onclick="showLead('${c.id}')"><div class="row1"><div><div class="street">${c.owner||c.street}</div><div class="sub">${c.interactions.length} interactions</div></div><span class="pill" style="background:var(--${c.status==='client'?'v':'g'}d);color:var(--${c.status==='client'?'v':'g'})">${c.status}</span></div></div>`).join(''):'')}
function showLead(id){const c=CUST.find(x=>x.id===id);if(!c)return;$('rpIn').innerHTML=`<div class="rp-h"><h2><i class="fas fa-user" style="color:var(--p)"></i> Lead</h2><button class="xb" onclick="closeRP()"><i class="fas fa-times"></i></button></div><div class="rp-body"><h3 style="font:800 14px var(--f);margin-bottom:8px">${c.owner||c.street}</h3><div class="gc" style="padding:10px;margin-bottom:8px"><div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">${[['Phone',c.phone||'—'],['Status',c.status],['First',new Date(c.firstSeen).toLocaleDateString()],['Visits',c.interactions.length]].map(([l,v])=>`<div><div style="font:500 7px var(--f);color:var(--t3);text-transform:uppercase">${l}</div><div style="font:600 10px var(--f);margin-top:1px">${v}</div></div>`).join('')}</div></div>${c.interactions.slice(-8).reverse().map(i=>`<div class="log-entry" style="padding:6px"><div style="width:6px;height:6px;border-radius:50%;background:${COL[i.type]||'var(--gr)'};margin-top:4px;flex-shrink:0"></div><div><span style="font:600 9px var(--f)">${i.type}</span> <span style="font:400 7px var(--f);color:var(--t3)">${new Date(i.date).toLocaleString()}</span></div></div>`).join('')}</div>`;$('rp').classList.add('open')}

// ═══ MARKERS ═══
function mkMk(a){const c=COL[a.status]||'#8E8E93';const m=L.marker([a.lat,a.lng],{icon:L.divIcon({className:'mic',html:`<div class="pin ${a.status==='scheduled'?'pulse':''}" style="background:${c}"><i class="fas ${ICO[a.status]||'fa-home'}"></i></div>`,iconSize:[22,32],iconAnchor:[11,32],popupAnchor:[0,-32]})}).addTo(map);m.bindPopup(`<div class="pop"><h3>${a.street}</h3><p>${a.city} · <span class="pill pill-${a.status}">${a.status}</span>${a.value?' · '+a.value:''}</p><div class="pop-b"><button class="btn btn-s btn-p" onclick="detail('${a.id}')"><i class="fas fa-edit"></i></button><button class="btn btn-s btn-ok" onclick="qUp('${a.id}')"><i class="fas fa-arrow-right"></i></button><button class="btn btn-s btn-g" onclick="openSV(${a.lat},${a.lng},'${esc(a.street)}')"><i class="fas fa-street-view"></i></button></div></div>`,{className:'cpop',maxWidth:250});MK[a.id]=m}
function reMk(a){if(MK[a.id])map.removeLayer(MK[a.id]);mkMk(a)}

// ═══ CRUD ═══
function startPin(){pinM=!pinM;$('pinBtn').classList.toggle('on',pinM);map.getContainer().style.cursor=pinM?'crosshair':'';if(pinM)msg('info','Pin','Click map [P]');closeFab()}
function openAddrForm(lat,lng,st,ci,zi){$('amT').textContent='Add';$('amId').value='';$('amSt').value=st||'';$('amCi').value=ci||'Deer Park';$('amZi').value=zi||'77536';$('amLa').value=lat?parseFloat(lat).toFixed(6):'';$('amLn').value=lng?parseFloat(lng).toFixed(6):'';$('amSs').value='pending';$('amPr').value='normal';$('amOw').value='';$('amPh').value='';$('amEm').value='';$('amTe').value='';$('amNo').value='';$('amVal').value='';$('amFollow').value='';$('amComp').value='';openOv('addrOv')}
function editAddr(id){const a=A.find(x=>x.id===id);if(!a)return;$('amT').textContent='Edit';$('amId').value=a.id;$('amSt').value=a.street;$('amCi').value=a.city;$('amZi').value=a.zip;$('amLa').value=a.lat;$('amLn').value=a.lng;$('amSs').value=a.status;$('amPr').value=a.priority||'normal';$('amOw').value=a.owner||'';$('amPh').value=a.phone||'';$('amEm').value=a.email||'';$('amTe').value=a.assigned||'';$('amNo').value=a.notes||'';$('amVal').value=a.value||'';$('amFollow').value=a.followUp||'';$('amComp').value=a.competitor||'';openOv('addrOv')}
async function saveAddr(){const eid=$('amId').value,st=$('amSt').value.trim(),lat=parseFloat($('amLa').value),lng=parseFloat($('amLn').value);if(!st)return msg('error','Error','Street needed');if(isNaN(lat)||isNaN(lng))return msg('error','Error','Coords needed');if(!eid&&isDuplicate(st,lat,lng))return msg('warning','Duplicate','This address may already exist');const o={street:st,city:$('amCi').value.trim()||'Deer Park',zip:$('amZi').value.trim()||'77536',lat,lng,status:$('amSs').value,priority:$('amPr').value,owner:$('amOw').value.trim(),phone:$('amPh').value.trim(),email:$('amEm').value.trim(),assigned:$('amTe').value,notes:$('amNo').value.trim(),value:$('amVal').value,followUp:$('amFollow').value,competitor:$('amComp').value.trim(),updatedAt:new Date().toISOString()};if(eid){const i=A.findIndex(x=>x.id===eid);if(i>=0){A[i]={...A[i],...o};reMk(A[i]);upsertCust(A[i]);addLog('update','Updated',st)}}else{idc.a++;const a={id:'a'+idc.a,...o,createdAt:new Date().toISOString(),visits:[],timeSpent:0};A.push(a);mkMk(a);upsertCust(a);addLog('add','Added',st);map.flyTo([lat,lng],18,{duration:.4})}await saveAll();upStats();render();closeOv('addrOv');msg('success','Saved',st)}
async function delAddr(id){if(!confirm('Delete?'))return;A=A.filter(x=>x.id!==id);if(MK[id]){map.removeLayer(MK[id]);delete MK[id]}addLog('delete','Deleted','');await saveAll();upStats();render();closeRP();msg('warning','Deleted','')}
async function qUp(id){const a=A.find(x=>x.id===id);if(!a)return;const f=['pending','scheduled','visited','interested','converted'];const ci=f.indexOf(a.status);const ns=f[Math.min(ci+1,f.length-1)];a.status=ns;a.updatedAt=new Date().toISOString();a.visits.push({date:new Date().toISOString(),status:ns});upsertCust(a);addLog('status',a.street+' → '+ns,'');if(ns==='converted')addLog('convert','🎉 '+a.street,'');reMk(a);await saveAll();upStats();render();msg('success','→ '+ns,a.street)}
async function setDir(id,s){const a=A.find(x=>x.id===id);if(!a)return;a.status=s;a.updatedAt=new Date().toISOString();a.visits.push({date:new Date().toISOString(),status:s});upsertCust(a);addLog('status',a.street+' → '+s,'');if(s==='converted')addLog('convert','🎉','');reMk(a);await saveAll();upStats();render();detail(id);msg('success','→ '+s,'')}

// ═══ RENDER ═══
function render(){const el=$('cards'),fa=getF();$('cnt').textContent=fa.length;if(!fa.length){el.innerHTML='<div style="text-align:center;padding:24px;color:var(--t3)"><i class="fas fa-map-marked-alt" style="font-size:24px;margin-bottom:6px;display:block;opacity:.4"></i><p style="font:600 10px var(--f)">No addresses</p></div>';return}el.innerHTML=fa.map(a=>{const sel=batchSel.has(a.id);const hasDND=DND.some(d=>d.addressId===a.id);const hasReminder=a.followUp&&a.followUp<=new Date().toISOString().split('T')[0]&&a.status!=='converted';return`<div class="acard s-${a.status} ${sel?'selected':''}" onclick="detail('${a.id}');openSV(${a.lat},${a.lng},'${esc(a.street)}')">${hasReminder?'<div class="reminder-dot"></div>':''}${hasDND?'<div class="dnd-badge">DND</div>':''}<div class="row1"><div><div class="street">${a.street}${a.value?' <span style="color:var(--o);font-size:8px">'+a.value+'</span>':''}</div><div class="sub">${a.city} ${a.zip}${a.owner?' · '+a.owner:''}${a.competitor?' · 🏷️'+a.competitor:''}</div></div><span class="pill pill-${a.status}">${a.status}</span></div><div class="btns"><input type="checkbox" ${sel?'checked':''} style="accent-color:var(--p);width:12px;height:12px;cursor:pointer" onclick="event.stopPropagation();toggleBatch('${a.id}',event)"><button class="sb" onclick="event.stopPropagation();flyTo('${a.id}')"><i class="fas fa-crosshairs"></i></button><button class="sb" onclick="event.stopPropagation();openSV(${a.lat},${a.lng},'${esc(a.street)}')"><i class="fas fa-street-view"></i></button><button class="sb" onclick="event.stopPropagation();qUp('${a.id}')"><i class="fas fa-arrow-right"></i></button><button class="sb" onclick="event.stopPropagation();genSlip('${a.id}')"><i class="fas fa-receipt"></i></button></div></div>`}).join('')}
function getF(){let f=[...A];if(filt!=='all')f=f.filter(a=>a.status===filt);const q=$('searchIn').value.toLowerCase();if(q.length>=2)f=f.filter(a=>a.street.toLowerCase().includes(q)||(a.owner||'').toLowerCase().includes(q));return f}
function upStats(){$('sT').textContent=A.length;$('sV').textContent=A.filter(a=>['visited','interested','converted','declined','not-home'].includes(a.status)).length;$('sI').textContent=A.filter(a=>a.status==='interested').length;$('sC').textContent=A.filter(a=>a.status==='converted').length}

// ═══ DETAIL ═══
function detail(id){const a=A.find(x=>x.id===id);if(!a)return;const c=COL[a.status];$('rpIn').innerHTML=`<div class="rp-h"><h2 style="color:${c}"><i class="fas ${ICO[a.status]}"></i> Detail</h2><button class="xb" onclick="closeRP()"><i class="fas fa-times"></i></button></div><div class="rp-body"><div style="text-align:center;margin-bottom:12px"><h3 style="font:800 14px var(--f)">${a.street}</h3><p style="font:400 10px var(--f);color:var(--t2)">${a.city}, TX ${a.zip}</p><span class="pill pill-${a.status}" style="margin-top:4px;display:inline-block">${a.status.toUpperCase()}</span>${a.value?` <span style="color:var(--o);font:700 10px var(--f)">${a.value}</span>`:''}</div><div style="display:flex;gap:3px;margin-bottom:8px"><button class="btn btn-g btn-s" style="flex:1" onclick="openSV(${a.lat},${a.lng},'${esc(a.street)}')"><i class="fas fa-street-view"></i> Street</button><button class="btn btn-g btn-s" onclick="window.open('https://www.google.com/maps/@${a.lat},${a.lng},150m/data=!3m1!1e3','_blank')"><i class="fas fa-cube"></i> 3D</button></div><div class="gc" style="padding:10px;margin-bottom:8px"><div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">${[['Owner',a.owner||'—'],['Phone',a.phone||'—'],['Team',a.assigned||'—'],['Priority',(a.priority||'normal').toUpperCase()],['Follow-up',a.followUp||'—'],['Competitor',a.competitor||'—']].map(([l,v])=>`<div><div style="font:500 7px var(--f);color:var(--t3);text-transform:uppercase">${l}</div><div style="font:600 10px var(--f);margin-top:1px">${v}</div></div>`).join('')}</div></div>${a.notes?`<div class="gc" style="padding:8px;margin-bottom:8px;font:400 9px var(--f);color:var(--t2)">${a.notes}</div>`:''}<div style="margin-bottom:8px"><div style="font:500 7px var(--f);color:var(--t3);text-transform:uppercase;margin-bottom:3px">Status</div><div style="display:flex;flex-wrap:wrap;gap:2px">${Object.keys(COL).map(s=>`<button class="btn btn-s ${a.status===s?'btn-p':'btn-g'}" onclick="setDir('${a.id}','${s}')" style="font-size:7px">${s}</button>`).join('')}</div></div>${a.visits&&a.visits.length?`<div style="margin-bottom:8px"><div style="font:500 7px var(--f);color:var(--t3);text-transform:uppercase;margin-bottom:3px">History (${a.visits.length})</div>${a.visits.slice(-5).reverse().map(v=>`<div class="gc" style="padding:5px;margin-bottom:2px;display:flex;align-items:center;gap:5px"><div style="width:5px;height:5px;border-radius:50%;background:${COL[v.status]}"></div><span style="font:600 9px var(--f)">${v.status}</span><span style="font:400 7px var(--f);color:var(--t3)">${new Date(v.date).toLocaleString()}</span></div>`).join('')}</div>`:''}<div style="display:flex;gap:3px"><button class="btn btn-p" style="flex:1" onclick="editAddr('${a.id}')"><i class="fas fa-edit"></i> Edit</button><button class="btn btn-g" onclick="flyTo('${a.id}')"><i class="fas fa-crosshairs"></i></button><button class="btn btn-no btn-s" onclick="delAddr('${a.id}')"><i class="fas fa-trash"></i></button></div><div style="display:flex;gap:3px;margin-top:4px"><button class="btn btn-g btn-s btn-w" onclick="genSlip('${a.id}')"><i class="fas fa-receipt"></i> Slip</button><button class="btn btn-g btn-s btn-w" onclick="addDND('${a.id}')"><i class="fas fa-ban"></i> DND</button></div></div>`;$('rp').classList.add('open');map.closePopup()}
function closeRP(){$('rp').classList.remove('open')}
function flyTo(id){const a=A.find(x=>x.id===id);if(a){map.flyTo([a.lat,a.lng],19,{duration:.5});setTimeout(()=>{if(MK[id])MK[id].openPopup()},600)}}
function genSlip(id){const a=A.find(x=>x.id===id);if(!a)return;const div=document.createElement('div');div.style.cssText='width:400px;padding:24px;background:#fff;border-radius:16px;font-family:-apple-system,sans-serif;color:#111;position:fixed;top:-9999px;left:-9999px';div.innerHTML=`<div style="display:flex;align-items:center;gap:10px;margin-bottom:16px;border-bottom:2px solid #007AFF;padding-bottom:12px"><div style="width:36px;height:36px;background:#007AFF;border-radius:10px;display:grid;place-items:center"><i class="fas fa-broom" style="color:#fff;font-size:16px"></i></div><div><div style="font-weight:800;font-size:14px">Maid Bridge</div><div style="font-size:10px;color:#666">${new Date().toLocaleDateString()}</div></div></div><div style="font-size:20px;font-weight:900">${a.street}</div><div style="color:#555;font-size:13px;margin-bottom:16px">${a.city}, TX ${a.zip}</div>${a.owner?`<div style="font-size:12px"><b>Contact:</b> ${a.owner}</div>`:''}${a.phone?`<div style="font-size:12px"><b>Phone:</b> ${a.phone}</div>`:''}<div style="margin-top:16px;padding:10px;background:#f0f7ff;border-radius:10px;font-size:11px;color:#007AFF;font-weight:700">🧹 Spotless clean — ask about our first-visit discount!</div>`;document.body.appendChild(div);html2canvas(div,{scale:2,backgroundColor:'#fff'}).then(c=>{div.remove();c.toBlob(b=>{const u=URL.createObjectURL(b);const l=document.createElement('a');l.href=u;l.download=`slip_${a.street.replace(/\s/g,'_')}.png`;l.click();URL.revokeObjectURL(u)})});msg('success','Slip',a.street)}

// ═══ TABS ═══
function doFilt(s,el){filt=s;document.querySelectorAll('.fc').forEach(c=>c.classList.remove('on'));el.classList.add('on');render();A.forEach(a=>{if(MK[a.id])MK[a.id].setOpacity(s==='all'||a.status===s?1:.08)})}
function sTab(t,el){document.querySelectorAll('.st').forEach(x=>x.classList.remove('on'));el.classList.add('on');['cards','filEl','blocksP','todayP','custP','logsP','dndP','funnelP','statsEl'].forEach(h=>{const e=$(h);if(e)e.classList.add('hidden')});$('statsEl').classList.remove('hidden');if(t==='addr'){$('filEl').classList.remove('hidden');$('cards').classList.remove('hidden')}else if(t==='blocks'){$('blocksP').classList.remove('hidden');renderBlocks()}else if(t==='today'){$('todayP').classList.remove('hidden');renderToday()}else if(t==='cust'){$('custP').classList.remove('hidden');renderCust()}else if(t==='logs'){$('logsP').classList.remove('hidden');renderLogs()}else if(t==='dnd'){$('dndP').classList.remove('hidden');renderDND()}else if(t==='funnel'){$('funnelP').classList.remove('hidden');renderFunnel()}}

// ═══ BLOCKS ═══
function drawBlock(){msg('info','Draw','Dbl-click to finish');let pts=[],tmp=null;const ck=e=>{pts.push([e.latlng.lat,e.latlng.lng]);if(tmp)map.removeLayer(tmp);if(pts.length>1)tmp=L.polygon(pts,{color:'#007AFF',fillOpacity:.08,weight:1.5,dashArray:'5,4'}).addTo(map)};const dbl=()=>{map.off('click',ck);map.off('dblclick',dbl);if(pts.length<3){if(tmp)map.removeLayer(tmp);return}const nm=prompt('Name:','Block '+(Z.length+1));if(!nm){if(tmp)map.removeLayer(tmp);return}idc.z++;if(tmp)map.removeLayer(tmp);const pl=L.polygon(pts,{color:'#007AFF',fillOpacity:.12,weight:1.5,dashArray:'5,4',fillColor:'#007AFF'}).addTo(drawnZ);pl.zid='z'+idc.z;pl.bindTooltip(nm,{permanent:true,direction:'center'});Z.push({id:'z'+idc.z,name:nm,bounds:pts,createdAt:new Date().toISOString(),addressCount:A.filter(a=>pip([a.lat,a.lng],pts)).length});saveAll();renderBlocks();addLog('add','Block: '+nm,'');msg('success','Created',nm)};map.on('click',ck);map.on('dblclick',dbl)}
function pip(pt,poly){let ins=false;for(let i=0,j=poly.length-1;i<poly.length;j=i++){const xi=poly[i][0],yi=poly[i][1],xj=poly[j][0],yj=poly[j][1];if(((yi>pt[1])!==(yj>pt[1]))&&(pt[0]<(xj-xi)*(pt[1]-yi)/(yj-yi)+xi))ins=!ins}return ins}
function renderBlocks(){$('blocksP').innerHTML=`<div class="sec-h"><span>Blocks</span><button class="btn btn-s btn-p" onclick="drawBlock()"><i class="fas fa-plus"></i></button></div>`+(Z.length?Z.map(z=>`<div class="sbl" style="position:relative"><div onclick="map.fitBounds(${JSON.stringify(z.bounds)},{padding:[30,30]})"><h4>${z.name}</h4><p>${z.addressCount||0} addresses</p></div><button class="btn btn-s btn-no" style="position:absolute;top:8px;right:8px;padding:4px 6px;font-size:10px" onclick="deleteBlock('${z.id}')" title="Delete block"><i class="fas fa-trash"></i></button></div>`).join(''):'')}
async function deleteBlock(id){if(!confirm('Delete this block? This will not delete addresses.'))return;const zIdx=Z.findIndex(z=>z.id===id);if(zIdx===-1)return;const z=Z[zIdx];Z.splice(zIdx,1);drawnZ.eachLayer(l=>{if(l.zid===id)drawnZ.removeLayer(l)});await saveAll();renderBlocks();addLog('delete','Deleted block',z.name);msg('warning','Deleted',z.name)}

// ═══ TODAY ═══
function renderToday(){const el=$('todayP');const td=new Date().toISOString().split('T')[0];const ts=SC.filter(s=>s.date===td);if(!ts.length){el.innerHTML='<div style="padding:16px;text-align:center;color:var(--t3)"><p>No schedule</p></div>';return}el.innerHTML=ts.map(sc=>{const sa=A.filter(a=>sc.addresses.includes(a.id));const done=sa.filter(a=>['visited','interested','converted','declined','not-home'].includes(a.status)).length;const pct=sa.length?Math.round(done/sa.length*100):0;return`<div class="gc" style="padding:10px;margin-bottom:6px"><div style="display:flex;justify-content:space-between"><h4 style="font:700 11px var(--f)">${sc.team}</h4><span style="font:800 10px var(--f);color:var(--p)">${pct}%</span></div><div class="prog"><div class="progf" style="width:${pct}%;background:var(--p)"></div></div><div style="font:400 8px var(--f);color:var(--t3);margin-top:2px">${done}/${sa.length}</div></div>`}).join('')+`<div style="display:flex;gap:4px;padding:10px"><button class="btn btn-p btn-w btn-s" onclick="openDispMdl()"><i class="fas fa-paper-plane"></i> Dispatch</button><button class="btn btn-no btn-w btn-s" onclick="openBulkRouteDelete()"><i class="fas fa-trash"></i> Bulk Delete</button></div>`}

// ═══ ROUTE MANAGEMENT ═══
function openRouteBuilder(){const pts=A.filter(a=>a.status==='scheduled'||a.status==='pending');if(!pts.length)return msg('warning','Route','Need addresses');buildRoute(pts);$('legendBox').style.display='none'}
function buildRoute(pts){clearRoute();const sorted=[];let cur={lat:routeOrigin.lat,lng:routeOrigin.lng};const rem=[...pts];while(rem.length){let b=0,bd=Infinity;rem.forEach((a,i)=>{const d=hav(cur.lat,cur.lng,a.lat,a.lng);if(d<bd){bd=d;b=i}});sorted.push(rem.splice(b,1)[0]);cur=sorted[sorted.length-1]}let imp=true,it=0;while(imp&&it<80){imp=false;it++;for(let i=0;i<sorted.length-1;i++)for(let j=i+2;j<sorted.length;j++){const d1=hav(sorted[i].lat,sorted[i].lng,sorted[i+1].lat,sorted[i+1].lng)+hav(sorted[j].lat,sorted[j].lng,(j+1<sorted.length?sorted[j+1].lat:routeOrigin.lat),(j+1<sorted.length?sorted[j+1].lng:routeOrigin.lng));const d2=hav(sorted[i].lat,sorted[i].lng,sorted[j].lat,sorted[j].lng)+hav(sorted[i+1].lat,sorted[i+1].lng,(j+1<sorted.length?sorted[j+1].lat:routeOrigin.lat),(j+1<sorted.length?sorted[j+1].lng:routeOrigin.lng));if(d2<d1){sorted.splice(i+1,j-i,...sorted.slice(i+1,j+1).reverse());imp=true}}}const ll=[[routeOrigin.lat,routeOrigin.lng],...sorted.map(a=>[a.lat,a.lng])];routeL=L.polyline(ll,{color:'#007AFF',weight:3,opacity:.8,dashArray:'8,5'}).addTo(map);let off=0;const ani=setInterval(()=>{off--;if(!routeL){clearInterval(ani);return}routeL.setStyle({dashOffset:off+''})},35);sorted.forEach((a,i)=>{routeMks.push(L.marker([a.lat,a.lng],{icon:L.divIcon({className:'mic',html:`<div style="width:20px;height:20px;border-radius:6px;background:var(--p);display:grid;place-items:center;font:800 8px var(--f);color:#fff;box-shadow:0 2px 8px var(--pg);border:2px solid #fff">${i+1}</div>`,iconSize:[20,20],iconAnchor:[10,10]}),zIndexOffset:900}).addTo(map))});let dist=0;for(let i=1;i<ll.length;i++)dist+=hav(ll[i-1][0],ll[i-1][1],ll[i][0],ll[i][1]);const mi=(dist*.621371).toFixed(1);$('rSt').textContent=sorted.length;$('rDi').textContent=mi;$('rTi').textContent=Math.round(sorted.length*8+parseFloat(mi)*2);$('rteON').textContent=routeOrigin.name;$('rteOA').textContent=routeOrigin.addr||'';$('rteStops').innerHTML=sorted.map((a,i)=>`<div class="rte-stop" onclick="flyTo('${a.id}')"><div class="rte-stop-num">${i+1}</div><div style="flex:1;min-width:0"><div class="sn">${a.street}</div><div class="sd">${a.status}${a.owner?' · '+a.owner:''}</div></div></div>`).join('');$('rtePanel').classList.add('vis');map.fitBounds(routeL.getBounds(),{padding:[40,40]});addLog('route','Route',sorted.length+' stops');msg('success','Route',sorted.length+' stops, '+mi+' mi')}
function hav(a,b,c,d){const R=6371,dLa=(c-a)*Math.PI/180,dLn=(d-b)*Math.PI/180;const x=Math.sin(dLa/2)**2+Math.cos(a*Math.PI/180)*Math.cos(c*Math.PI/180)*Math.sin(dLn/2)**2;return R*2*Math.atan2(Math.sqrt(x),Math.sqrt(1-x))}
function clearRoute(){if(routeL){map.removeLayer(routeL);routeL=null}routeMks.forEach(m=>map.removeLayer(m));routeMks=[];$('rtePanel').classList.remove('vis');$('legendBox').style.display=''}
function changeOrigin(){pendOID=null;$('oHQ').classList.add('sel');$('oList').innerHTML=A.map(a=>`<div class="sbl" onclick="pickO('${a.id}',this)"><h4 style="font-size:10px">${a.street}</h4></div>`).join('');openOv('originOv')}
function setOHQ(el){document.querySelectorAll('#originOv .sbl').forEach(s=>s.classList.remove('sel'));el.classList.add('sel');pendOID=null}
function pickO(id,el){document.querySelectorAll('#originOv .sbl').forEach(s=>s.classList.remove('sel'));el.classList.add('sel');$('oHQ').classList.remove('sel');pendOID=id}
function confirmOrigin(){if(pendOID){const a=A.find(x=>x.id===pendOID);if(a)routeOrigin={lat:a.lat,lng:a.lng,name:a.street,addr:a.city}}else routeOrigin={...HQ};closeOv('originOv');const pts=A.filter(a=>a.status==='scheduled'||a.status==='pending');if(pts.length)buildRoute(pts)}
function exportRoute(){const stops=$('rteStops').querySelectorAll('.rte-stop');let csv='"#","Address","Info"\n';stops.forEach((s,i)=>{csv+=`"${i+1}","${s.querySelector('.sn').textContent}","${s.querySelector('.sd').textContent}"\n`});dlFile(csv,'Route.csv','text/csv');msg('success','Exported','')}
// ═══ BULK ROUTE DELETE ═══
function openBulkRouteDelete(){const today=new Date().toISOString().split('T')[0];const todaySchedules=SC.filter(s=>s.date===today);if(!todaySchedules.length)return msg('warning','No routes','No routes scheduled for today');let html=`<div class="sec-h"><span>Bulk Delete Routes</span><button class="btn btn-s btn-no" onclick="closeBulkRouteDelete()"><i class="fas fa-times"></i></span></div>`;html+=`<div style="padding:10px;margin-bottom:10px"><p style="font:500 10px var(--f);color:var(--t2)">Select routes to delete:</p>`;todaySchedules.forEach(s=>{const addrCount=s.addresses.length;const team=s.team||'Unassigned';html+=`<div class="gc" style="padding:8px;margin-bottom:4px;display:flex;align-items:center;gap:8px"><input type="checkbox" class="route-delete-cb" data-route-id="${s.id}" style="accent-color:var(--r)"><div style="flex:1"><div style="font:700 11px var(--f)">${team}</div><div style="font:400 8px var(--f);color:var(--t3)">${addrCount} addresses · ${s.date}</div></div></div>`});html+=`</div><div style="display:flex;gap:4px;padding:0 10px 10px"><button class="btn btn-s btn-no" onclick="deleteSelectedRoutes()"><i class="fas fa-trash"></i> Delete Selected</button><button class="btn btn-s btn-g" onclick="closeBulkRouteDelete()">Cancel</button></div>`;const panel=document.createElement('div');panel.id='bulkRouteDeletePanel';panel.className='mp';panel.style.cssText='position:absolute;top:60px;left:10px;background:var(--bg);border-radius:8px;box-shadow:0 4px 12px var(--pg);max-width:280px;z-index:1000';panel.innerHTML=html;document.querySelector('.map-area').appendChild(panel)}
function closeBulkRouteDelete(){const panel=$('bulkRouteDeletePanel');if(panel)panel.remove()}
async function deleteSelectedRoutes(){const checkboxes=document.querySelectorAll('.route-delete-cb:checked');if(!checkboxes.length)return msg('warning','No selection','Select routes to delete');if(!confirm(`Delete ${checkboxes.length} route(s)? This will reset addresses to pending status.`))return;const deletedIds=[];for(const cb of checkboxes){const routeId=cb.dataset.routeId;const sIdx=SC.findIndex(s=>s.id===routeId);if(sIdx!==-1){const schedule=SC[sIdx];deletedIds.push(schedule.id);schedule.addresses.forEach(addrId=>{const addr=A.find(a=>a.id===addrId);if(addr&&addr.status==='scheduled'){addr.status='pending';addr.updatedAt=new Date().toISOString();if(MK[addrId])reMk(addr)}});SC.splice(sIdx,1)}}await saveAll();upStats();render();closeBulkRouteDelete();addLog('delete','Bulk delete',`${deletedIds.length} routes deleted`);msg('success','Deleted',`${deletedIds.length} routes deleted`)}
// ═══ SCHEDULE MANAGEMENT ═══
function openSchedMdl(){selSA=[];tsA={};$('scZg').innerHTML=Z.length?Z.map(z=>`<div class="eo" onclick="pickScZ('${z.id}',this)"><i class="fas fa-map"></i><h5>${z.name}</h5></div>`).join(''):'';renderScA('');buildSlots();openOv('schedOv')}
function renderScA(q){$('scAL').innerHTML=A.filter(a=>(a.status==='pending'||a.status==='scheduled')&&(!q||a.street.toLowerCase().includes(q.toLowerCase()))).map(a=>`<div class="sbl ${selSA.includes(a.id)?'sel':''}" onclick="togScA('${a.id}',this)"><div style="display:flex;align-items:center;gap:5px"><input type="checkbox" ${selSA.includes(a.id)?'checked':''} style="pointer-events:none;accent-color:var(--p);width:12px;height:12px"><h4 style="font-size:9px">${a.street}</h4></div></div>`).join('')}
function filterScA(v){renderScA(v)}
function pickScZ(id,el){document.querySelectorAll('#scZg .eo').forEach(e=>e.classList.remove('sel'));el.classList.add('sel');const z=Z.find(x=>x.id===id);if(z&&z.bounds){selSA=[];A.forEach(a=>{if(pip([a.lat,a.lng],z.bounds)&&(a.status==='pending'||a.status==='scheduled'))selSA.push(a.id)});renderScA('');autoSlots()}}
function togScA(id,el){if(selSA.includes(id))selSA=selSA.filter(x=>x!==id);else selSA.push(id);el.classList.toggle('sel');el.querySelector('input').checked=selSA.includes(id);autoSlots()}
function buildSlots(){$('scSlots').innerHTML='';for(let h=9;h<=17;h++){const l=h>12?(h-12)+' PM':h+' AM';$('scSlots').innerHTML+=`<div class="tslot"><span class="tl">${l}</span><div class="tchips" id="ts${h}"><span style="color:var(--t3);font:400 7px var(--f)">—</span></div></div>`}}
function autoSlots(){const hrs=[];for(let h=9;h<=17;h++)hrs.push(h);tsA={};const per=Math.ceil(selSA.length/hrs.length);let idx=0;hrs.forEach(h=>{tsA[h]=[];for(let i=0;i<per&&idx<selSA.length;i++,idx++)tsA[h].push(selSA[idx]);const el=$('ts'+h);if(el)el.innerHTML=tsA[h].length?tsA[h].map(id=>{const a=A.find(x=>x.id===id);return a?`<span class="tc">${a.street}</span>`:''}).join(''):'<span style="color:var(--t3);font:400 7px var(--f)">—</span>'})}
async function saveSched(){if(!selSA.length)return msg('error','','Select addresses');idc.s++;SC.push({id:'s'+idc.s,date:$('scDt').value,team:$('scTm').value,notes:$('scNo').value,addresses:[...selSA],timeSlots:{...tsA},createdAt:new Date().toISOString()});selSA.forEach(id=>{const a=A.find(x=>x.id===id);if(a){a.status='scheduled';a.updatedAt=new Date().toISOString();reMk(a)}});await saveAll();upStats();render();addLog('schedule','Schedule',selSA.length);closeOv('schedOv');msg('success','Created',selSA.length+' stops')}

function toggleHeat(){if(hG){map.removeLayer(hG);hG=null;return}hG=L.layerGroup();A.forEach(a=>{const c=a.status==='converted'?'rgba(48,209,88,.35)':a.status==='interested'?'rgba(48,209,88,.18)':a.status==='visited'?'rgba(255,159,10,.18)':'rgba(142,142,147,.06)';L.circle([a.lat,a.lng],{radius:45,color:'transparent',fillColor:c,fillOpacity:.5}).addTo(hG)});hG.addTo(map)}

// ═══ EXPORT ═══
function openExpMdl(){openOv('expOv')}
function eT(t,el){expTyp=t;document.querySelectorAll('#expOv .eo').forEach(e=>e.classList.remove('sel'));el.classList.add('sel')}
function eF(f,el){expFmt=f;document.querySelectorAll('.efb').forEach(b=>{b.classList.remove('btn-p');b.classList.add('btn-g')});el.classList.remove('btn-g');el.classList.add('btn-p')}
function doExp(){let d=[];if(expTyp==='today'){const td=new Date().toISOString().split('T')[0];d=A.filter(a=>SC.filter(s=>s.date===td).flatMap(s=>s.addresses).includes(a.id));if(!d.length)d=A.filter(a=>a.status==='scheduled')}else if(expTyp==='filtered')d=getF();else if(expTyp==='leads'){let c='Name,Address,Phone,Status\n';CUST.forEach(x=>{c+=(x.owner||'')+','+x.street+','+(x.phone||'')+','+x.status+'\n'});dlFile(c,'Leads.csv','text/csv');closeOv('expOv');return}else d=A;if(!d.length)return msg('warning','','No data');if(expFmt==='csv'){let c='Street,City,ZIP,Status,Owner,Phone,Team,Value,Competitor\n';d.forEach(a=>{c+=`${a.street},${a.city},${a.zip},${a.status},${a.owner||''},${a.phone||''},${a.assigned||''},${a.value||''},${a.competitor||''}\n`});dlFile(c,'MaidBridge.csv','text/csv')}else if(expFmt==='json')dlFile(JSON.stringify({addresses:d,leads:CUST},null,2),'MaidBridge.json','application/json');else{const h=`<!DOCTYPE html><html><head><style>body{font-family:-apple-system;padding:20px;color:#111}h1{color:#007AFF;font-size:16px}table{width:100%;border-collapse:collapse;margin-top:10px}th{background:#007AFF;color:#fff;padding:5px 7px;text-align:left;font-size:8px}td{padding:3px 7px;border-bottom:1px solid #eee;font-size:8px}</style></head><body><h1>Maid Bridge</h1><table><thead><tr><th>#</th><th>Address</th><th>Status</th><th>Owner</th><th>Phone</th><th>Value</th></tr></thead><tbody>${d.map((a,i)=>`<tr><td>${i+1}</td><td>${a.street}</td><td>${a.status}</td><td>${a.owner||''}</td><td>${a.phone||''}</td><td>${a.value||''}</td></tr>`).join('')}</tbody></table><script>window.onload=()=>window.print()<\/script></body></html>`;window.open(URL.createObjectURL(new Blob([h],{type:'text/html'})))}addLog('export','Export',d.length);closeOv('expOv');msg('success','Exported',d.length)}
function dlFile(c,n,t){const b=new Blob([c],{type:t});const u=URL.createObjectURL(b);const a=document.createElement('a');a.href=u;a.download=n;document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(u)}
function importCSV(ev){const f=ev.target.files[0];if(!f)return;const rd=new FileReader();rd.onload=async e=>{const lines=e.target.result.split('\n').filter(l=>l.trim());const hd=lines[0].split(',').map(h=>h.trim().toLowerCase().replace(/"/g,''));let ct=0;for(let i=1;i<lines.length;i++){const v=lines[i].split(',').map(x=>x.trim().replace(/"/g,''));const si=hd.findIndex(h=>h.includes('street')||h.includes('address'));if(si>=0&&v[si]){if(isDuplicate(v[si],0,0))continue;idc.a++;const a={id:'a'+idc.a,street:v[si],city:v[hd.findIndex(h=>h.includes('city'))]||'Deer Park',zip:v[hd.findIndex(h=>h.includes('zip'))]||'77536',lat:parseFloat(v[hd.findIndex(h=>h.includes('lat'))])||HQ.lat+(Math.random()-.5)*.01,lng:parseFloat(v[hd.findIndex(h=>h.includes('lng')||h.includes('lon'))])||HQ.lng+(Math.random()-.5)*.01,status:'pending',priority:'normal',owner:v[hd.findIndex(h=>h.includes('owner')||h.includes('name'))]||'',phone:v[hd.findIndex(h=>h.includes('phone'))]||'',email:'',notes:'',assigned:'',value:'',followUp:'',competitor:'',createdAt:new Date().toISOString(),updatedAt:new Date().toISOString(),visits:[]};A.push(a);mkMk(a);upsertCust(a);ct++}}await saveAll();upStats();render();addLog('add','CSV',ct);msg('success','Import',ct)};rd.readAsText(f);ev.target.value=''}

