// ═══ ANALYTICS ═══
function openStats(){const t=A.length;const sc={};Object.keys(COL).forEach(s=>sc[s]=A.filter(a=>a.status===s).length);const cr=t?(sc.converted/t*100).toFixed(1):0;const teams=['Team Alpha','Team Bravo','Team Charlie'];$('rpIn').innerHTML=`<div class="rp-h"><h2><i class="fas fa-chart-pie" style="color:var(--p)"></i> Analytics</h2><button class="xb" onclick="closeRP()"><i class="fas fa-times"></i></button></div><div class="rp-body"><div style="display:grid;grid-template-columns:1fr 1fr;gap:5px;margin-bottom:12px"><div style="background:var(--p);border-radius:12px;padding:12px;color:#fff"><div style="font:900 20px var(--f)">${t}</div><div style="font:400 8px var(--f);opacity:.8">Total</div></div><div style="background:var(--g);border-radius:12px;padding:12px;color:#fff"><div style="font:900 20px var(--f)">${cr}%</div><div style="font:400 8px var(--f);opacity:.8">Conversion</div></div></div><div style="margin-bottom:12px"><div style="font:600 8px var(--f);color:var(--t3);text-transform:uppercase;margin-bottom:6px">Pipeline</div>${Object.entries(sc).map(([s,c])=>{const p=t?(c/t*100):0;return`<div style="margin-bottom:4px"><div style="display:flex;justify-content:space-between;margin-bottom:1px"><span style="font:500 9px var(--f);color:var(--t2);text-transform:capitalize">${s.replace('-',' ')}</span><span style="font:700 9px var(--f)">${c}</span></div><div class="prog"><div class="progf" style="width:${p}%;background:${COL[s]}"></div></div></div>`}).join('')}</div><div style="font:600 8px var(--f);color:var(--t3);text-transform:uppercase;margin-bottom:6px">Team Leaderboard</div>${teams.map(tm=>{const ta=A.filter(a=>a.assigned===tm);const cv=ta.filter(a=>a.status==='converted').length;const vi=ta.filter(a=>['visited','interested','converted'].includes(a.status)).length;return`<div class="gc" style="padding:8px;margin-bottom:4px;display:flex;justify-content:space-between;align-items:center"><div><div style="font:700 11px var(--f)">${tm}</div><div style="font:400 8px var(--f);color:var(--t3)">${ta.length} addr · ${cv} conv · ${vi} visited</div></div><div style="font:900 14px var(--f);color:var(--g)">${ta.length?(cv/ta.length*100).toFixed(0):0}%</div></div>`}).join('')}<div style="margin-top:12px"><div style="font:600 8px var(--f);color:var(--t3);text-transform:uppercase;margin-bottom:6px">Property Value Distribution</div>${['$$$$','$$$','$$','$',''].map(v=>{const c=A.filter(a=>a.value===v).length;const label=v||'Unknown';return`<div style="display:flex;justify-content:space-between;padding:3px 0;font:500 9px var(--f);color:var(--t2)"><span>${label}</span><span style="font-weight:700;color:var(--o)">${c}</span></div>`}).join('')}</div></div>`;$('rp').classList.add('open')}

