function navTo(v,el){document.querySelectorAll('.tab').forEach(t=>t.classList.remove('on'));el.classList.add('on');if(v==='sched')openSchedMdl();else if(v==='stats')openStats();else if(v==='dispatch')openDispMdl();else if(v==='sms')openOv('smsOv')}
function toggleSide(){$('side').classList.toggle('shut')}
function toggleFab(){$('fab').classList.toggle('open')}
function closeFab(){$('fab').classList.remove('open')}
function openOv(id){$(id).classList.add('on')}
function closeOv(id){$(id).classList.remove('on')}
function fitAll(){if(!A.length){map.flyTo([HQ.lat,HQ.lng],16);return}map.fitBounds(L.featureGroup(Object.values(MK)).getBounds(),{padding:[30,30]})}
function goHQ(){map.flyTo([HQ.lat,HQ.lng],18,{duration:.6})}
function resetAll(){filt='all';document.querySelectorAll('.fc').forEach(c=>c.classList.remove('on'));document.querySelector('.fc').classList.add('on');$('searchIn').value='';batchSel.clear();$('batchBar').classList.remove('vis');A.forEach(a=>{if(MK[a.id])MK[a.id].setOpacity(1)});render();map.flyTo([HQ.lat,HQ.lng],17,{duration:.6});clearRoute();if(hG){map.removeLayer(hG);hG=null}closeSV();$('kbPanel').classList.remove('vis');msg('info','Reset','')}
function msg(type,title,text){const w=$('toasts');const ic={success:'fa-check',error:'fa-times',info:'fa-info',warning:'fa-exclamation'};const t=document.createElement('div');t.className='toast '+type;t.innerHTML=`<div class="t-i"><i class="fas ${ic[type]}"></i></div><div><div class="t-t">${title}</div><div class="t-m">${text||''}</div></div>`;w.appendChild(t);setTimeout(()=>{t.style.opacity='0';t.style.transform='translateX(40px)';t.style.transition='all .3s';setTimeout(()=>t.remove(),300)},2500)}
